1	'use strict';
2	/**
3	 * crawl.js - the P3 evidence crawler entry. Produces the EvidenceBundle.corpus the pure facts layer
4	 * consumes ({pages:[{url,title,text,jsonLd,ogSiteName?}], footerText?}) plus a coverage report.
5	 *
6	 * ALL network + clock effects are INJECTED so node:test runs offline and deterministically:
7	 *   crawl(domain, { fetchFn, deadlineMs, maxPages, width, now, timers, fetchXml, log, sector, rules,
8	 *                   followDocuments }) -> { domain, corpus, unreachable, reason, documents, coverage,
9	 *                   telemetry, notes }
10	 *   fetchFn(url) -> Promise<{ ok, status, body, finalUrl?, contentType? }>   (the ONLY way bytes arrive)
11	 *
12	 * Doctrine preserved:
13	 *   - E-236 parallelism: parallel page fetches (width from opts, NO floor), parallel sitemap discovery,
14	 *     TIER-1-first ordering applied BEFORE the page cap (discover.js).
15	 *   - Rule 9: every fetch is wrapped in a hard Promise.race deadline (pool.withDeadline); the pool's
16	 *     wall-clock deadline is a CAP, never a floor (Rule 8).
17	 *   - C-024/C-025: the corpus char cap is generous and env-guarded - a sub-floor env value THROWS.
18	 *   - C-031/C-032/C-038: a login/challenge/error/SPA-shell response never enters the corpus or flips
19	 *     reachability; an unreadable site yields an unreachable bundle (nothing asserted).
20	 *   - C-033/C-034: the homepage footer is a mandatory surface, and footer-linked documents are followed
21	 *     (evidence/documents), with unparsed PDFs demoting dependent obligations in the coverage report.
22	 */
23	
24	const crypto = require('crypto');
25	const safeFetch = require('../../tools/lib/safe-fetch.js');
26	const { withDeadline, runPool } = require('./pool.js');
27	const extract = require('./extract.js');
28	const discover = require('./discover.js');
29	const coverage = require('./coverage-contract.js');
30	const { collectDocuments } = require('../documents/documents.js');
31	
32	const CORPUS_CAP_FLOOR = 50000;      // below this, footer disclosures fall past the cut (russell-cooke, C-024)
33	const CORPUS_CAP_DEFAULT = 500000;
34	const PAGES_FLOOR = 5;
35	const PAGES_DEFAULT = 120;
36	const WIDTH_DEFAULT = 8;
37	const DEADLINE_DEFAULT = 45000;
38	
39	// resolveCap(envName, def, floor) -> the effective cap. An env value below the safety floor THROWS
40	// (caution.md C-025: a budget must never be silently zeroed to nothing via env).
41	function resolveCap(envName, def, floor) {
42	  const raw = process.env[envName];
43	  if (raw === undefined || raw === '') return def;
44	  const n = Number(raw);
45	  if (!Number.isFinite(n) || n < floor) {
46	    throw new Error(envName + '=' + JSON.stringify(raw) + ' is below the safety floor of ' + floor + '; a corpus budget is a cap, never a silent zeroing (caution.md C-025)');
47	  }
48	  return n;
49	}
50	
51	function normaliseDomain(domain) {
52	  return String(domain || '').trim().replace(/^https?:\/\//i, '').replace(/\/.*$/, '').replace(/^www\./i, '').toLowerCase();
53	}
54	
55	// fetchPage(fetchFn, url, perPageMs, timers) -> the fetch result, or null on failure/timeout (Rule 9:
56	// a slow page degrades to null and the crawl continues; it never hangs).
57	async function fetchPage(fetchFn, url, perPageMs, timers) {
58	  try { return await withDeadline(() => fetchFn(url), perPageMs, timers); }
59	  catch (e) { return null; /* FAIL-OPEN: a per-page deadline/exception yields a null slot handled by the caller's telemetry, never a hang or a swallowed hard error. */ }
60	}
61	
62	// makeFetchXml(fetchFn, perPageMs, timers) -> the injected XML/robots fetcher discover.js needs: returns
63	// the body text on a 200, '' otherwise (never throws), each read behind the same hard deadline.
64	function makeFetchXml(fetchFn, perPageMs, timers) {
65	  return (url) => fetchPage(fetchFn, url, perPageMs, timers).then((r) => (r && r.ok && r.body) ? String(r.body) : '');
66	}
67	
68	// contentPageFrom(url, res, cap) -> a corpus page ({url,title,text,jsonLd,ogSiteName?}) when res is real,
69	// readable CONTENT (not a login/challenge/error/shell, C-031/C-038); else null with the reason class.
70	function contentPageFrom(url, res, cap) {
71	  if (!res || !res.body) return { page: null, klass: res && res.status ? 'error' : 'unreachable' };
72	  const klass = extract.pageContentClass(res.status, res.body);
73	  if (klass !== 'content') return { page: null, klass };
74	  const page = extract.buildPage(res.finalUrl || url, res.body);
75	  let truncated = false;
76	  if (page.text.length > cap) { truncated = true; page.text = page.text.slice(0, cap); }
77	  return { page, klass: 'content', truncated, bodyHash: crypto.createHash('sha1').update(String(res.body)).digest('hex') };
78	}
79	
80	// accumulateCorpus(fetchList, results, home, homeUrl, cap) -> { pages, truncated, telemetry }. Content
81	// pages are deduped by body hash (soft-404s collapse); every non-content class is counted, never asserted.
82	function accumulateCorpus(fetchList, results, cap) {
83	  const pages = [];
84	  const seenBody = new Set();
85	  const telemetry = { pages_tried: fetchList.length, content: 0, login: 0, challenge: 0, error: 0, empty: 0, unreachable: 0 };
86	  let truncated = false;
87	  for (let i = 0; i < fetchList.length; i++) {
88	    const { page, klass, truncated: t, bodyHash } = contentPageFrom(fetchList[i], results[i], cap);
89	    telemetry[klass] = (telemetry[klass] || 0) + 1;
90	    if (!page) continue;
91	    if (seenBody.has(bodyHash)) continue;
92	    seenBody.add(bodyHash);
93	    truncated = truncated || Boolean(t);
94	    pages.push(page);
95	  }
96	  return { pages, truncated, telemetry };
97	}
98	
99	// footerLinks(homeHtml, base, accepted) -> same-site hrefs found inside the homepage <footer> (where the
100	// policy/PDF links live, C-034); empty when there is no footer region.
101	function footerLinks(homeHtml, base, accepted) {
102	  const m = /<footer\b[^>]*>([\s\S]*?)<\/footer\s*>/i.exec(String(homeHtml || ''));
103	  if (!m) return [];
104	  return discover.discoverLinks(m[1], base, accepted);
105	}
106	
107	// blockReason(homeRes, homeKlass, pageCount) -> an honest reason string when the crawl read no content.
108	function blockReason(homeRes, homeKlass, pageCount) {
109	  if (pageCount > 0) return null;
110	  if (homeKlass === 'challenge') return 'anti_bot_challenge';
111	  if (homeKlass === 'login') return 'login_wall';
112	  if (homeRes && homeRes.status >= 400) return 'http_' + homeRes.status;
113	  if (homeKlass === 'empty') return 'js_rendered_empty_shell';
114	  return 'no_readable_pages';
115	}
116	
117	// buildCoverage(pages, opts, truncated, unparsedClasses) -> the coverage report: the site-level render
118	// class always, plus the per-rule covered|screened contract when catalogue rules were supplied.
119	function buildCoverage(pages, opts, truncated, unparsedClasses) {
120	  const site = coverage.computeCoverage(pages, opts.sector);
121	  const out = { site };
122	  if (Array.isArray(opts.rules)) out.perRule = coverage.coverageFor(opts.rules, pages, { truncated, unparsedClasses });
123	  return out;
124	}
125	
126	// crawl(domain, opts) -> the evidence bundle. Thin orchestrator: resolve budgets, fetch the homepage,
127	// discover links + sitemap in parallel, order Tier-1-first then cap, fetch the corpus in parallel, follow
128	// footer documents, and assemble the corpus + coverage report.
129	async function crawl(domain, opts = {}) {
130	  const dom = normaliseDomain(domain);
131	  if (!dom || !dom.includes('.')) throw new Error('crawl: a fetchable domain (with a public suffix) is required, got ' + JSON.stringify(domain));
132	  if (typeof opts.fetchFn !== 'function') throw new Error('crawl: opts.fetchFn is required (all network is dependency-injected)');
133	  const log = typeof opts.log === 'function' ? opts.log : () => {};
134	  const notes = [];
135	  const record = (kind, msg) => { notes.push({ kind, msg }); log(kind, msg); };
136	
137	  const cap = typeof opts.corpusMaxChars === 'number' ? opts.corpusMaxChars : resolveCap('CORPUS_MAX_CHARS', CORPUS_CAP_DEFAULT, CORPUS_CAP_FLOOR);
138	  const maxPages = typeof opts.maxPages === 'number' ? opts.maxPages : resolveCap('MAX_CRAWL_PAGES', PAGES_DEFAULT, PAGES_FLOOR);
139	  const width = typeof opts.width === 'number' && opts.width > 0 ? opts.width : WIDTH_DEFAULT;
140	  const deadlineMs = typeof opts.deadlineMs === 'number' ? opts.deadlineMs : DEADLINE_DEFAULT;
141	  const perPageMs = Math.min(deadlineMs, opts.perPageMs || 20000);
142	  const base = 'https://' + dom;
143	  const accepted = new Set([safeFetch.registrableDomain(dom)]);
144	  const fetchXml = typeof opts.fetchXml === 'function' ? opts.fetchXml : makeFetchXml(opts.fetchFn, perPageMs, opts.timers);
145	
146	  const home = await fetchPage(opts.fetchFn, base + '/', perPageMs, opts.timers);
147	  const homeHtml = home && home.body ? String(home.body) : '';
148	  const homeKlass = extract.pageContentClass(home ? home.status : 0, homeHtml);
149	  if (homeKlass !== 'content') record('homepage-not-content', base + '/ classified as "' + homeKlass + '"; no content asserted from it (C-031/C-038)');
150	
151	  const [links, sitemap] = await Promise.all([
152	    Promise.resolve(homeHtml ? discover.discoverLinks(homeHtml, base, accepted) : []),
153	    discover.discoverSitemap(dom, accepted, fetchXml).catch(() => []),
154	  ]);
155	  const fetchList = discover.orderCandidates(base + '/', [...links, ...sitemap], accepted, maxPages);
156	
157	  const homeUrl = base + '/';
158	  const results = await runPool(fetchList, width, deadlineMs,
159	    (u) => (u === homeUrl ? Promise.resolve(home) : fetchPage(opts.fetchFn, u, perPageMs, opts.timers)), opts.now);
160	  const { pages, truncated, telemetry } = accumulateCorpus(fetchList, results, cap);
161	  if (truncated) record('corpus-truncated', 'a page exceeded the ' + cap + '-char corpus cap; absence claims on it demote to needs-review (C-024)');
162	
163	  const footerText = extract.extractFooterText(homeHtml);
164	  let docResult = { documents: [], unparsed: [], unparsedClasses: new Set(), notes: [] };
165	  if (opts.followDocuments !== false && pages.length) {
166	    docResult = await collectDocuments(footerLinks(homeHtml, base, accepted),
167	      { fetchFn: opts.fetchFn, deadlineMs: perPageMs, timers: opts.timers, log: record });
168	  }
169	
170	  const unreachable = pages.length === 0;
171	  const reason = blockReason(home, homeKlass, pages.length);
172	  const corpus = { pages, footerText: footerText || undefined };
173	  return {
174	    domain: dom,
175	    corpus,
176	    unreachable,
177	    reason,
178	    documents: { records: docResult.documents, unparsed: docResult.unparsed },
179	    coverage: buildCoverage(pages, opts, truncated, docResult.unparsedClasses),
180	    telemetry: { ...telemetry, pages_captured: pages.length, truncated, via: unreachable ? 'none' : 'direct' },
181	    notes,
182	  };
183	}
184	
185	module.exports = { crawl, resolveCap, normaliseDomain, accumulateCorpus, contentPageFrom, footerLinks, blockReason };
186

1	'use strict';
2	/**
3	 * discover.js - link + sitemap discovery and the E-236 Tier-1-first ordering.
4	 *
5	 * Two properties this file exists to preserve:
6	 *  - QUERY-STRING URLs are crawled (caution.md C-027): CMS policy pages live at /privacy?page_id=42, so
7	 *    link discovery keeps '?' (only the fragment is dropped). isNonCrawlable in the safe-fetch door drops
8	 *    mailto/tel/js schemes; a query string is never dropped.
9	 *  - TIER-1 legal pages (privacy, cookies, terms, complaints) are ordered ahead of any commercial page
10	 *    and BEFORE the page cap applies (caution.md C-026): orderCandidates ranks by tier, THEN slices to the
11	 *    cap, so a Tier-1 page discovered LAST still survives a cap smaller than the candidate count.
12	 *
13	 * Sitemap discovery fans out in PARALLEL (E-236): the robots.txt sitemap roots race together and each
14	 * root's child sitemaps are fetched together; the identical URL set is produced with the idling removed.
15	 * The XML fetch is INJECTED (fetchXml) so this module is pure/offline and node:test drives it with mocks.
16	 * Host identity is decided ONLY through the tools/lib/safe-fetch.js parsed-host door.
17	 */
18	
19	const safeFetch = require('../../tools/lib/safe-fetch.js');
20	const { extractHrefs } = require('./extract.js');
21	
22	// Guessed policy-path backstop (privacy/cookie/terms FIRST) for sites whose links/sitemap miss them.
23	const POLICY_PATHS = [
24	  '/privacy', '/privacy-policy', '/cookies', '/cookie-policy', '/terms', '/terms-and-conditions',
25	  '/legal', '/complaints', '/accessibility', '/data-protection',
26	];
27	
28	const TIER1_RX = /privacy|cookie|terms|legal|gdpr|data[-_ ]protection|accessibility|complaint|modern[-_ ]slavery|disclaimer|imprint|disclosure|safeguard|regulat|compliance|confidentialit|datenschutz|rgpd/i;
29	const TIER2_RX = /about|contact|service|pricing|prices|fees|returns|refund|shipping|delivery|team|locations|offices|sector/i;
30	const BLOG_RX = /\/blog|\/news|\/insights|\/press|\/article|\/resources|\/stories|\/updates|\/knowledge|\/20\d\d\//i;
31	
32	// classifyTier(url) -> the crawl priority tier of a URL by PATH (not host): 'tier1' policy/legal,
33	// 'tier2' commercial, 'blog' editorial, 'other'. Tier-1 wins even if the URL also matches a lower tier.
34	function classifyTier(url) {
35	  const u = String(url || '');
36	  if (TIER1_RX.test(u)) return 'tier1';
37	  if (TIER2_RX.test(u)) return 'tier2';
38	  if (BLOG_RX.test(u)) return 'blog';
39	  return 'other';
40	}
41	
42	const TIER_RANK = { tier1: 1, tier2: 2, blog: 3, other: 4 };
43	function normaliseUrl(u) { return String(u).split('#')[0].replace(/\/$/, '').toLowerCase(); }
44	
45	// discoverLinks(html, base, accepted) -> the same-registrable-site hrefs on a page, resolved absolute,
46	// query strings kept (C-027), fragments/mailto/tel/js dropped, deduped in discovery order.
47	function discoverLinks(html, base, accepted) {
48	  const out = [];
49	  const seen = new Set();
50	  for (const href of extractHrefs(html)) {
51	    if (safeFetch.isNonCrawlable(href)) continue;
52	    let abs;
53	    try { abs = new URL(href, base).toString(); } catch (e) { continue; /* FAIL-OPEN: an unparseable href is not a crawl target; skipping it hides nothing (the URL simply is not a link). */ }
54	    if (!safeFetch.sameRegistrableSite(abs, accepted)) continue;
55	    const clean = abs.split('#')[0];
56	    const key = normaliseUrl(clean);
57	    if (seen.has(key)) continue;
58	    seen.add(key);
59	    out.push(clean);
60	  }
61	  return out;
62	}
63	
64	// parseSitemapLocs(xml) -> { pageUrls, childSitemaps } from a <urlset>/<sitemapindex> body.
65	function parseSitemapLocs(xml) {
66	  const locs = (String(xml || '').match(/<loc>\s*([^<\s]+)\s*<\/loc>/gi) || [])
67	    .map((x) => x.replace(/<\/?loc>/gi, '').trim());
68	  return {
69	    childSitemaps: locs.filter((u) => /sitemap.*\.xml/i.test(u)).slice(0, 8),
70	    pageUrls: locs.filter((u) => !/\.xml/i.test(u)),
71	  };
72	}
73	
74	// sitemapRoots(domain, robotsBody) -> the sitemap roots to try: robots.txt Sitemap: directives first
75	// (authoritative), then the conventional roots.
76	function sitemapRoots(domain, robotsBody) {
77	  const roots = [];
78	  for (const m of String(robotsBody || '').matchAll(/(?:^|\n)\s*sitemap:\s*(\S+)/gi)) roots.push(m[1].trim());
79	  roots.push('https://' + domain + '/sitemap.xml', 'https://' + domain + '/sitemap_index.xml', 'https://' + domain + '/sitemap-index.xml');
80	  return roots;
81	}
82	
83	// collectSitemapPages(body, accepted, fetchXml) -> same-site page URLs from one root body, following its
84	// child sitemaps in PARALLEL (E-236). Returns [] when the body yields no same-site pages.
85	async function collectSitemapPages(body, accepted, fetchXml) {
86	  const { pageUrls, childSitemaps } = parseSitemapLocs(body);
87	  const urls = pageUrls.filter((u) => safeFetch.sameRegistrableSite(u, accepted));
88	  const childBodies = await Promise.all(childSitemaps.map((cs) => fetchXml(cs).catch(() => '')));
89	  for (const cb of childBodies) {
90	    for (const u of parseSitemapLocs(cb).pageUrls) if (safeFetch.sameRegistrableSite(u, accepted)) urls.push(u);
91	  }
92	  return urls;
93	}
94	
95	// discoverSitemap(domain, accepted, fetchXml) -> same-site page URLs from the sitemap. Roots race in
96	// PARALLEL; the first root that yields same-site pages wins (identical set, no sequential idling).
97	async function discoverSitemap(domain, accepted, fetchXml) {
98	  const robots = await fetchXml('https://' + domain + '/robots.txt').catch(() => '');
99	  const roots = sitemapRoots(domain, robots);
100	  const bodies = await Promise.all(roots.map((r) => fetchXml(r).catch(() => '')));
101	  for (const body of bodies) {
102	    if (!body) continue;
103	    const urls = await collectSitemapPages(body, accepted, fetchXml);
104	    if (urls.length) return urls;
105	  }
106	  return [];
107	}
108	
109	// guessedPaths(accepted) -> the policy-path backstop across every accepted registrable host.
110	function guessedPaths(accepted) {
111	  const out = [];
112	  for (const reg of accepted) for (const p of POLICY_PATHS) out.push('https://' + reg + p);
113	  return out;
114	}
115	
116	// orderCandidates(homeUrl, discovered, accepted, maxPages) -> the deduped, same-site fetch list ordered
117	// TIER-1-FIRST and THEN capped (C-026): the homepage leads, then Tier-1 (legal), Tier-2 (commercial),
118	// blog, other; a stable sort preserves discovery order within a tier; the cap is applied LAST so Tier-1
119	// survives even when it was discovered last and the cap is smaller than the candidate count.
120	function orderCandidates(homeUrl, discovered, accepted, maxPages) {
121	  const homeKey = normaliseUrl(homeUrl);
122	  const pool = [homeUrl, ...guessedPaths(accepted), ...(discovered || [])];
123	  const seen = new Set();
124	  const ranked = [];
125	  for (const u of pool) {
126	    if (!safeFetch.sameRegistrableSite(u, accepted)) continue;
127	    const key = normaliseUrl(u);
128	    if (seen.has(key)) continue;
129	    seen.add(key);
130	    ranked.push({ url: u, rank: key === homeKey ? 0 : TIER_RANK[classifyTier(u)] });
131	  }
132	  ranked.sort((a, b) => a.rank - b.rank); // stable in Node: ties keep discovery order
133	  const capped = ranked.slice(0, maxPages).map((r) => r.url);
134	  return capped;
135	}
136	
137	module.exports = {
138	  POLICY_PATHS, classifyTier, discoverLinks, discoverSitemap, orderCandidates,
139	  parseSitemapLocs, guessedPaths, normaliseUrl,
140	};
141

1	'use strict';
2	/**
3	 * pool.js - the E-236 parallel primitive and the Rule 9 hard-deadline wrapper.
4	 *
5	 * E-236 restored a 43s crawl to 6.9s with identical accuracy by removing the IDLING, not the work: I/O-
6	 * bound page fetches run in a bounded-concurrency pool with a wall-clock deadline that is a CAP (it stops
7	 * STARTING new work past the deadline), never a floor (Constitution Rule 8 - no Math.max, no minimum wait).
8	 * The pool width comes from the caller; nothing here widens or floors it.
9	 *
10	 * Rule 9: every external step is wrapped in a hard Promise.race deadline, so a slow dependency degrades
11	 * the crawl (a null slot) and never hangs it (the 752s stuck-Chromium class). Timers are INJECTABLE so
12	 * node:test drives this deterministically with no real wall-clock wait.
13	 */
14	
15	// withDeadline(factory, ms, timers) -> a promise that settles with factory()'s value, or REJECTS once
16	// `ms` elapses, whichever is first. timers defaults to the globals; a test injects a fake pair. The
17	// timer is always cleared so a resolved factory never leaves a dangling handle keeping the process alive.
18	function withDeadline(factory, ms, timers) {
19	  const T = timers || { setTimeout, clearTimeout };
20	  let timer = null;
21	  const deadline = new Promise((_resolve, reject) => {
22	    timer = T.setTimeout(() => reject(new Error('deadline exceeded after ' + ms + 'ms')), ms);
23	    if (timer && typeof timer.unref === 'function') timer.unref();
24	  });
25	  return Promise.race([Promise.resolve().then(factory), deadline])
26	    .finally(() => { if (timer) T.clearTimeout(timer); });
27	}
28	
29	// runPool(items, width, deadlineMs, fn, now) -> results aligned to `items` (null where a fetch failed or
30	// the wall-clock deadline was reached before that item STARTED). `now` is injectable (defaults to
31	// Date.now) so a test can prove the deadline is a cap: advance the clock past deadlineMs and the pool
32	// stops starting work, leaving the un-started tail null - it never blocks and never floors.
33	async function runPool(items, width, deadlineMs, fn, now) {
34	  const clock = typeof now === 'function' ? now : Date.now;
35	  const out = new Array(items.length);
36	  let idx = 0;
37	  const start = clock();
38	  async function worker() {
39	    for (;;) {
40	      const i = idx++;
41	      if (i >= items.length) return;
42	      if (clock() - start > deadlineMs) { out[i] = null; continue; } // CAP: never START past the deadline
43	      try { out[i] = await fn(items[i], i); }
44	      catch (e) { out[i] = null; /* FAIL-OPEN: one page's failure degrades to a null slot and the crawl continues (E-236 tolerance); the null is visible to the caller's telemetry, not swallowed silently. */ }
45	    }
46	  }
47	  const lanes = items.length === 0 ? 0 : Math.min(width, items.length);
48	  await Promise.all(Array.from({ length: lanes }, worker));
49	  return out;
50	}
51	
52	module.exports = { withDeadline, runPool };
53

1	'use strict';
2	/**
3	 * extract.js - the crawler's HTML -> evidence extractor. THE ONE producer of stripped visible text for
4	 * the corpus (caution.md C-012: sector/rule matching never runs on <script>/<style>/markup noise; the
5	 * evidence quote is cut from exactly this text, C-035). Pure and synchronous over an HTML string; no
6	 * network, no clock, no env. Every corpus page and the footer surface (C-034) come out of here.
7	 *
8	 * pageContentClass() is the C-031/C-032/C-038 guard: a login/challenge/error/SPA-shell response is
9	 * classified by its CONTENT, not its byte count, so a login or bot-wall page can never flip a site to
10	 * "reachable" or become an absence-finding surface.
11	 */
12	
13	const NAMED_ENTITIES = {
14	  amp: '&', lt: '<', gt: '>', quot: '"', apos: "'", nbsp: ' ', '#39': "'",
15	  ndash: '-', mdash: '-', hellip: '...', copy: '(c)', reg: '(R)', trade: '(TM)',
16	  pound: '£', euro: '€', middot: '·', bull: '•',
17	};
18	
19	function decodeEntities(s) {
20	  return String(s).replace(/&(#x?[0-9a-fA-F]+|[a-zA-Z]+);/g, (m, g) => {
21	    const key = g.toLowerCase();
22	    if (Object.prototype.hasOwnProperty.call(NAMED_ENTITIES, key)) return NAMED_ENTITIES[key];
23	    if (g[0] === '#') {
24	      const code = (g[1] === 'x' || g[1] === 'X') ? parseInt(g.slice(2), 16) : parseInt(g.slice(1), 10);
25	      if (Number.isFinite(code) && code >= 9 && code <= 0x10ffff) {
26	        try { return String.fromCodePoint(code); } catch (e) { return ' '; /* FAIL-OPEN: an invalid code point in hostile source HTML degrades to a space, the honest substitute; nothing is hidden. */ }
27	      }
28	    }
29	    return m;
30	  });
31	}
32	
33	// stripHtml(html) -> visible text only. Raw-text and non-content elements are dropped whole (tolerant of
34	// "</script >" whitespace, caution.md html-text D-01), block closers become newlines so footer lines
35	// survive, remaining tags become spaces, entities are decoded, whitespace is collapsed.
36	function stripHtml(html) {
37	  let s = String(html);
38	  s = s.replace(/<!--[\s\S]*?-->/g, ' ');
39	  s = s.replace(/<(script|style|noscript|template|svg|iframe|head)\b[\s\S]*?<\/\1\s*>/gi, ' ');
40	  s = s.replace(/<\/(p|div|li|ul|ol|h[1-6]|tr|td|th|section|article|footer|header|nav|br)\s*>/gi, '\n');
41	  s = s.replace(/<br\s*\/?>/gi, '\n');
42	  s = s.replace(/<[^>]+>/g, ' ');
43	  s = decodeEntities(s);
44	  s = s.replace(/[ \t\r\f\v]+/g, ' ');
45	  s = s.replace(/ ?\n ?/g, '\n');
46	  s = s.replace(/\n{3,}/g, '\n\n');
47	  return s.trim();
48	}
49	
50	function extractTitle(html) {
51	  const m = /<title[^>]*>([\s\S]*?)<\/title\s*>/i.exec(String(html));
52	  return m ? decodeEntities(m[1]).replace(/\s+/g, ' ').trim() : '';
53	}
54	
55	function extractOgSiteName(html) {
56	  const re = /<meta\b[^>]*>/gi;
57	  let m;
58	  while ((m = re.exec(String(html))) !== null) {
59	    if (!/property\s*=\s*["']og:site_name["']/i.test(m[0])) continue;
60	    const c = /content\s*=\s*["']([^"']*)["']/i.exec(m[0]);
61	    if (c) return decodeEntities(c[1]).trim();
62	  }
63	  return undefined;
64	}
65	
66	function extractJsonLd(html) {
67	  const out = [];
68	  const re = /<script\b[^>]*type\s*=\s*["']application\/ld\+json["'][^>]*>([\s\S]*?)<\/script\s*>/gi;
69	  let m;
70	  while ((m = re.exec(String(html))) !== null) {
71	    const raw = m[1].trim();
72	    if (!raw) continue;
73	    try { out.push(JSON.parse(raw)); }
74	    catch (e) { /* FAIL-OPEN: invalid JSON-LD on the live site is a fact about the site; record nothing, fabricate nothing (no partial-parse guesses). */ }
75	  }
76	  return out;
77	}
78	
79	// extractFooterText(html) -> the statutory-disclosure surface (C-034): the concatenated visible text of
80	// every <footer> region, else '' (the crawl caller may fall back to the page tail). Company number,
81	// registered office and SRA/authorisation strings live here; it is a MANDATORY detection surface.
82	function extractFooterText(html) {
83	  const out = [];
84	  const re = /<footer\b[^>]*>([\s\S]*?)<\/footer\s*>/gi;
85	  let m;
86	  while ((m = re.exec(String(html))) !== null) { const t = stripHtml(m[1]); if (t) out.push(t); }
87	  return out.join('\n').trim();
88	}
89	
90	// extractHrefs(html) -> every raw href value in the document (query strings kept, C-027). Resolution and
91	// same-site filtering are the crawl layer's job (via the tools/lib/safe-fetch.js parsed-host door).
92	function extractHrefs(html) {
93	  const out = [];
94	  const re = /href\s*=\s*["']([^"']+)["']/gi;
95	  let m;
96	  while ((m = re.exec(String(html))) !== null && out.length < 2000) out.push(decodeEntities(m[1]).trim());
97	  return out;
98	}
99	
100	function buildPage(url, html) {
101	  const page = { url, title: extractTitle(html), text: stripHtml(html), jsonLd: extractJsonLd(html) };
102	  const og = extractOgSiteName(html);
103	  if (og !== undefined) page.ogSiteName = og;
104	  return page;
105	}
106	
107	// ── content classification (C-031 / C-032 / C-038): never let a wall/login/error/shell flip reachable ──
108	const CHALLENGE_MARKERS = [
109	  'just a moment', 'attention required', 'checking your browser', 'verify you are human',
110	  'access denied', 'ddos protection', 'cf-challenge', 'enable javascript and cookies to continue',
111	  'captcha', 'request unsuccessful', 'incapsula', 'perimeterx', 'are you a robot',
112	];
113	const WALL_STATUSES = new Set([401, 403, 429, 503]);
114	const LOGIN_MARKERS = /(sign in|signin|log in|login|log ?into|please (?:sign|log) in|enter your (?:password|username)|forgot your password)/i;
115	
116	function looksChallenge(status, text, title) {
117	  if (WALL_STATUSES.has(status)) return true;
118	  const hay = ((title || '') + '\n' + String(text || '').slice(0, 2500)).toLowerCase();
119	  if (!hay.trim()) return false;
120	  return CHALLENGE_MARKERS.some((mk) => hay.includes(mk)) && String(text || '').length < 4000;
121	}
122	
123	// looksLogin: the WHOLE page is a sign-in gate, not a content page that merely links to a client login.
124	// Guarded by content dominance (thin visible text OR a password field on a short page), never byte count
125	// alone (caution.md C-031).
126	function looksLogin(html, text) {
127	  const t = String(text || '');
128	  if (!LOGIN_MARKERS.test((t + ' ' + extractTitle(html)))) return false;
129	  const hasPasswordField = /<input\b[^>]*type\s*=\s*["']password["']/i.test(String(html));
130	  if (t.length < 600) return true;
131	  return hasPasswordField && t.length < 1500;
132	}
133	
134	// looksSpaShell: HTTP 200, an HTML document, but near-zero visible text (C-032, royalparkpartners.com).
135	function looksSpaShell(html, text) {
136	  if (String(text || '').length >= 200) return false;
137	  const body = String(html || '');
138	  if (!/<html[\s>]/i.test(body) && !/<div/i.test(body)) return false;
139	  return /<div[^>]*id\s*=\s*["'](root|app|__next|___gatsby)["']/i.test(body) || /<script/i.test(body);
140	}
141	
142	// pageContentClass(status, html) -> 'content' | 'challenge' | 'login' | 'error' | 'empty'. Only 'content'
143	// enters the corpus and counts toward reachability; every other class is honestly withheld.
144	function pageContentClass(status, html) {
145	  const st = Number(status) || 0;
146	  if (st >= 500 || st === 404 || st === 410) return 'error';
147	  const text = stripHtml(html);
148	  if (looksChallenge(st, text, extractTitle(html))) return 'challenge';
149	  if (looksLogin(html, text)) return 'login';
150	  if (looksSpaShell(html, text)) return 'empty';
151	  if (text.length < 20) return 'empty';
152	  return 'content';
153	}
154	
155	module.exports = {
156	  decodeEntities, stripHtml, extractTitle, extractOgSiteName, extractJsonLd,
157	  extractFooterText, extractHrefs, buildPage, pageContentClass,
158	};
