155	
156	// hostOf(u, base) -> the lowercase, www-stripped hostname of u (resolved against base if relative), or
157	// '' when u is not a parseable URL. The ONLY way host identity is read; never a substring of the URL.
158	function hostOf(u, base) {
159	  try { return new URL(String(u), base || undefined).hostname.toLowerCase().replace(/^www\./, ''); }
160	  catch (e) { return ''; /* not a URL: no host (the caller treats '' as "not same site") */ }
161	}
162	
163	// The common multi-part public suffixes, so a subdomain (blog./help./uk.) and the www variant of the
164	// same registrable domain all count as the SAME SITE. Defaults to last-two-labels otherwise.
165	const MULTI_TLD = new Set([
166	  'co.uk', 'org.uk', 'gov.uk', 'ac.uk', 'me.uk', 'ltd.uk', 'plc.uk', 'net.uk', 'sch.uk', 'nhs.uk',
167	  'com.au', 'net.au', 'org.au', 'edu.au', 'gov.au', 'co.nz', 'org.nz', 'govt.nz', 'co.za', 'org.za',
168	  'com.sg', 'edu.sg', 'gov.sg', 'com.br', 'com.mx', 'co.in', 'net.in', 'org.in', 'co.jp', 'or.jp',
169	  'com.hk', 'com.cn', 'co.ae', 'gov.ae', 'com.tr', 'co.il', 'com.sa',
170	]);
171	
172	// registrableDomain(host) -> the registrable domain (eTLD+1) of a host string, www-stripped and
173	// port-stripped. Parsed from labels, never a substring of a URL.
174	function registrableDomain(host) {
175	  const h = String(host || '').toLowerCase().replace(/^www\./, '').replace(/:.*$/, '');
176	  const p = h.split('.');
177	  if (p.length <= 2) return h;
178	  return MULTI_TLD.has(p.slice(-2).join('.')) ? p.slice(-3).join('.') : p.slice(-2).join('.');
179	}
180	
181	// isSameHost(u, domain) -> true when u's HOST is `domain` or a subdomain of it. Never a substring test
182	// (isSameHost('https://evil.com/linkedin.com', 'linkedin.com') is FALSE; the old .includes() said TRUE).
183	function isSameHost(u, domain) {
184	  const h = hostOf(u);
