3	/**
4	 * ONE-DOOR: the semantic-duplication detector. THE most valuable analyser in the fleet.
5	 *
6	 * jscpd sees textual clones. This sees SEMANTIC clones: two different pieces of code that both PRODUCE the
7	 * same client-visible fact. The stale door is the one the client sees. This class has already shipped a P0
8	 * three times on the old estate: the ghost jurisdiction, the "Sector regulator" label, and the GBP 17.5M
9	 * fine that never reached the client.
10	 *
11	 * The contract lives in facts.json: every client-visible fact -> its ONE allowed producer path. Any file
12	 * outside the allowed producer that matches a fact's producer patterns is a second door, and this check
13	 * exits non-zero.
14	 *
15	 * Modes:
16	 *   node tools/one-door/check.js                      scan the engine source tree, exit 1 on any violation
17	 *   node tools/one-door/check.js --json <path>        also write findings JSON for the sweep normaliser
18	 *   node tools/one-door/check.js --calibrate          scan eval/calibration-known-bad/fixtures/ and REQUIRE
19	 *                                                     that seeded violations are found. Zero found = exit 1.
20	 *                                                     A zero you did not earn is a lie.
21	 */
22	const fs = require('fs');
23	const path = require('path');
24	
25	const { runGateCli, ROOT } = require('../lib/gate-cli');
26	
27	const FACTS_PATH = path.join(__dirname, 'facts.json');
28	const SCAN_DIRS = ['catalogue', 'evidence', 'facts', 'applicability', 'breach', 'llm', 'payload', 'mint', 'render-proof'];
