30	function loadFacts(factsPath) {
31	  // A manifest we cannot parse has NOT declared zero facts. Fail loud.
32	  const doc = JSON.parse(fs.readFileSync(factsPath || FACTS_PATH, 'utf8'));
33	  if (!Array.isArray(doc.facts) || doc.facts.length === 0) throw new Error('facts.json declares no facts');
34	  return doc.facts.map((f) => ({
35	    id: f.id,
36	    label: f.label,
37	    allowed: f.allowed_producers || [],
38	    patterns: f.patterns.map((p) => new RegExp(p, 'm')),
39	  }));
40	}
41	
42	function isAllowed(relPath, fact) {
43	  return fact.allowed.some((a) => (a.endsWith('/') ? relPath.startsWith(a) : relPath === a));
44	}
45	
46	// Scan one file's content. Returns violations: a match for a fact's producer pattern in a file that is not
47	// the fact's one allowed door.
48	function scanContent(relPath, content, facts) {
49	  const out = [];
50	  for (const fact of facts) {
51	    if (isAllowed(relPath, fact)) continue;
52	    for (const rx of fact.patterns) {
53	      const m = rx.exec(content);
54	      if (!m) continue;
55	      const line = content.slice(0, m.index).split('\n').length;
56	      out.push({
57	        fact: fact.id,
58	        label: fact.label,
59	        file: relPath,
60	        line,
61	        pattern: rx.source,
62	        excerpt: content.slice(m.index, m.index + 120).split('\n')[0],
63	        allowed: fact.allowed.join(', '),
64	      });
65	      break; // one violation per fact per file is enough; the door is the unit, not the match
66	    }
67	  }
68	  return out;
69	}
70	
71	const { listJsFiles } = require('../lib/fswalk');
72	
73	function scanTree(dirs, facts) {
74	  const violations = [];
75	  let scanned = 0;
76	  for (const dir of dirs) {
77	    for (const abs of listJsFiles(path.join(ROOT, dir), { skipTests: true })) {
78	      scanned++;
79	      const rel = path.relative(ROOT, abs).replace(/\\/g, '/');
80	      violations.push(...scanContent(rel, fs.readFileSync(abs, 'utf8'), facts));
81	    }
82	  }
83	  return { violations, scanned };
84	}
85	
86	// Self-test: prove the detector can see the class it exists to catch, using synthetic content in memory.
87	// If this fails, every green run this tool has ever produced is suspect.
88	function selfTest() {
89	  const facts = loadFacts();
90	  const bad = scanContent('breach/rogue.js',
91	    "const fine_high_gbp = 17500000;\nconst regulator = 'Information Commissioner';\n", facts);
92	  const badFn = scanContent('evidence/rogue2.js',
93	    "function detectJurisdiction(domain) { return 'UK'; }\n", facts);
94	  const good = scanContent('catalogue/compiled.js',
95	    "const fine_high_gbp = 17500000;\nconst regulator = 'Information Commissioner';\n", facts);
96	  const pass = bad.length >= 2 && badFn.length >= 1 && good.length === 0;
97	  return { pass, detail: 'synthetic second doors: ' + bad.length + ' violations (want >=2) + ' + badFn.length + ' jurisdiction-fn (want >=1); allowed door: ' + good.length + ' (want 0)' };
98	}
99	
100	function toFindings(violations) {
101	  return violations.map((v) => ({
102	    tool: 'one-door',
103	    ruleId: 'multiple-producers:' + v.fact,
104	    file: v.file,
105	    startLine: v.line,
106	    endLine: v.line,
107	    level: 'error',
108	    message: 'TWO DOORS: "' + v.label + '" produced outside its one allowed door (' + v.allowed + '). The stale door is the one the client sees.',
109	    snippet: v.excerpt,
110	  }));
111	}
112	
113	function main() {
114	  const facts = loadFacts();
115	  runGateCli({
116	    name: 'one-door',
117	    selfTest,
118	    scan: (dirs) => scanTree(dirs, facts),
119	    toFindings,
120	    scanDirs: SCAN_DIRS,
121	    summary: (r) => r.scanned + ' files scanned, ' + facts.length + ' facts declared, ' + r.violations.length + ' violations',
122	    calibrateSummary: (r) => r.scanned + ' fixture files, ' + r.violations.length + ' seeded violations found',
123	    violationLine: (v) => 'TWO DOORS [' + v.fact + '] ' + v.file + ':' + v.line + '  (allowed: ' + v.allowed + ')  ' + v.excerpt,
124	  });
125	}
126	
127	if (require.main === module) main();
128	module.exports = { loadFacts, scanContent, scanTree, selfTest, toFindings };
