1	#!/usr/bin/env node
2	'use strict';
3	/**
4	 * BUDGET-CAPS gate: budgets are caps, never floors (Constitution Rule 8, GAPS.md `budget-floor`).
5	 *
6	 * The old estate lost the "~45s any website" crawl because the SPA-render tail carried a 45-second FLOOR
7	 * via `Math.max(45, ...)` / `Math.max(20000, Math.floor(deadlineMs*0.6))`, so a few shells always cost at
8	 * least that long; E-236 restored a 43s crawl to 6.9s by deleting the floor. Separately, an unbounded
9	 * browser step held a mint hostage for 752s. This gate fails CI (AST scan, evidence/ only) on:
10	 *
11	 *   1. A `Math.max(...)` FLOOR on a time/budget value: a Math.max with a numeric-literal argument that is
12	 *      budget-associated - the value it initialises is named timeout/budget/deadline/wait/delay/ttl/...,
13	 *      OR one of its arguments references such an identifier (e.g. Math.max(20000, f(deadlineMs))).
14	 *   2. A setTimeout delay / AbortSignal.timeout / budget-named constant that is a numeric literal > 120s
15	 *      (120000ms): a deadline longer than two minutes is a hang budget, not a cap.
16	 *
17	 * A Math.min cap, a setTimeout(fn, 5000), and a non-time numeric (a byte/char ceiling not bound to a
18	 * budget name) are all spared. Engine: acorn is MANDATORY; without it the gate REFUSES (exit 2) rather
19	 * than approximate (Constitution Rule 4). String literals are invisible to acorn, so no false hits.
20	 *
21	 * Modes (tools/lib/gate-cli.js dialect):
22	 *   node tools/domain-gates/budget-caps.js               scan evidence/, exit 1 on any floor/oversize
23	 *   node tools/domain-gates/budget-caps.js --json <path> also write findings JSON for the sweep normaliser
24	 *   node tools/domain-gates/budget-caps.js --calibrate   scan eval/calibration-known-bad/fixtures/ and
25	 *                                                         REQUIRE the seeded floor to be caught
26	 */
27	const fs = require('fs');
28	const path = require('path');
29	
30	const { runGateCli, ROOT } = require('../lib/gate-cli');
31	const { listJsFiles } = require('../lib/fswalk');
32	
33	// evidence/ is the fetch/crawl/browser code where a floor or an oversize deadline does the damage. The
34	// gate lives in tools/, so scanning tools/ would flag the gate's own detection literals; evidence is scope.
35	const SCAN_DIRS = ['evidence'];
36	const SKIP_DIRS = /^(node_modules|\.git|out|packs|dist|fixtures)$/;
37	
38	const THRESHOLD_MS = 120000; // 120s. A time budget above this is a hang budget, not a cap.
39	const BUDGET_NAME_RX = /(timeout|budget|deadline|delay|backoff|linger|wait|ttl|sleep)/i;
40	
41	let acorn = null;
42	try { acorn = require('acorn'); }
43	catch (e) { acorn = null; /* FAIL-OPEN: acorn=null is the typed failure captured HERE; scanContent() REFUSES (exit 2) so the SYSTEM fails closed. acorn ships transitively via eslint. */ }
44	const FORCE_REFUSE = process.env.BUDGET_CAPS_ENGINE === 'refuse';
45	const useAcorn = Boolean(acorn) && !FORCE_REFUSE;
46	
47	// ── small AST predicates ──────────────────────────────────────────────────────────────────────────
48	function isMathMax(callee) {
49	  return Boolean(callee) && callee.type === 'MemberExpression' && !callee.computed &&
50	    callee.object && callee.object.type === 'Identifier' && callee.object.name === 'Math' &&
51	    callee.property && callee.property.name === 'max';
52	}
53	function isSetTimeout(callee) {
54	  if (!callee) return false;
55	  if (callee.type === 'Identifier') return callee.name === 'setTimeout';
56	  return callee.type === 'MemberExpression' && callee.property && callee.property.name === 'setTimeout';
57	}
58	function isAbortTimeout(callee) {
59	  return Boolean(callee) && callee.type === 'MemberExpression' &&
60	    callee.object && callee.object.type === 'Identifier' && callee.object.name === 'AbortSignal' &&
61	    callee.property && callee.property.name === 'timeout';
62	}
63	function isNumericLiteral(node) {
64	  return Boolean(node) && node.type === 'Literal' && typeof node.value === 'number';
65	}
66	function isOversizeLiteral(node) {
67	  return isNumericLiteral(node) && node.value > THRESHOLD_MS;
68	}
69	
70	// refsBudgetIdent(node) -> true when a budget-named identifier appears anywhere in this expression
71	// subtree (so Math.max(20000, Math.floor(deadlineMs*0.6)) is recognised as a floor on deadlineMs).
72	function refsBudgetIdent(node) {
73	  if (!node || typeof node !== 'object') return false;
74	  if (node.type === 'Identifier') return BUDGET_NAME_RX.test(node.name);
75	  for (const k of Object.keys(node)) {
76	    if (k === 'loc' || k === 'start' || k === 'end') continue;
77	    const v = node[k];
78	    if (Array.isArray(v)) { if (v.some(refsBudgetIdent)) return true; }
79	    else if (v && typeof v === 'object' && refsBudgetIdent(v)) return true;
80	  }
81	  return false;
82	}
83	
84	// isBudgetFloor(callNode, binding) -> the Math.max is a FLOOR on a budget: it has a numeric-literal arg
85	// AND is budget-associated (its binding name, or a referenced identifier, is budget-named).
86	function isBudgetFloor(callNode, binding) {
87	  const args = callNode.arguments || [];
88	  if (!args.some(isNumericLiteral)) return false;
89	  if (binding && BUDGET_NAME_RX.test(binding)) return true;
90	  return args.some(refsBudgetIdent);
91	}
92	
93	// ── binding context: the name a value-carrying child initialises (for the two budget-name rules) ─────
94	function targetName(node) {
95	  if (!node) return null;
96	  if (node.type === 'Identifier') return node.name;
97	  if (node.type === 'MemberExpression' && node.property && node.property.type === 'Identifier') return node.property.name;
98	  return null;
99	}
100	function keyName(key) {
101	  if (!key) return null;
102	  if (key.type === 'Identifier') return key.name;
103	  if (key.type === 'Literal') return String(key.value);
104	  return null;
105	}
106	// valueChildBinding(node, key) -> the binding name to pass to the value-carrying child (init/right/value),
107	// else null. A value nested inside a CallExpression's arguments resets to null (it is not the binding).
108	function valueChildBinding(node, key) {
109	  if (node.type === 'VariableDeclarator' && key === 'init') return targetName(node.id);
110	  if (node.type === 'AssignmentExpression' && key === 'right') return targetName(node.left);
111	  if (node.type === 'Property' && key === 'value') return keyName(node.key);
112	  return null;
113	}
114	
115	// ── flaggers ────────────────────────────────────────────────────────────────────────────────────────
116	function flagCall(node, binding, relPath, line) {
117	  const out = [];
118	  if (isMathMax(node.callee) && isBudgetFloor(node, binding)) {
119	    out.push({ file: relPath, line, kind: 'budget-floor', message: 'Math.max() imposes a FLOOR on a time/budget value; a budget is a cap, never a minimum (Rule 8, E-236)' });
120	  }
121	  if (isSetTimeout(node.callee) && isOversizeLiteral(node.arguments && node.arguments[1])) {
122	    out.push({ file: relPath, line, kind: 'oversize-deadline', message: 'setTimeout delay literal ' + node.arguments[1].value + 'ms exceeds the 120s hard-deadline cap (Rule 9)' });
123	  }
124	  if (isAbortTimeout(node.callee) && isOversizeLiteral(node.arguments && node.arguments[0])) {
125	    out.push({ file: relPath, line, kind: 'oversize-deadline', message: 'AbortSignal.timeout literal ' + node.arguments[0].value + 'ms exceeds the 120s hard-deadline cap (Rule 9)' });
126	  }
127	  return out;
128	}
129	function flagLiteral(node, binding, relPath, line) {
130	  if (!isOversizeLiteral(node)) return [];
131	  if (!binding || !BUDGET_NAME_RX.test(binding)) return [];
132	  return [{ file: relPath, line, kind: 'oversize-deadline', message: 'budget "' + binding + '" is set to a literal ' + node.value + 'ms, exceeding the 120s hard-deadline cap (Rule 9)' }];
133	}
134	
135	// ── walk: carry the binding name to value-carrying children only ──────────────────────────────────────
136	function walk(node, binding, relPath, violations) {
137	  if (!node || typeof node !== 'object') return;
138	  if (Array.isArray(node)) { for (const n of node) walk(n, null, relPath, violations); return; }
139	  if (typeof node.type !== 'string') return;
140	  const line = (node.loc && node.loc.start.line) || 1;
141	  if (node.type === 'CallExpression') violations.push(...flagCall(node, binding, relPath, line));
142	  else if (node.type === 'Literal') violations.push(...flagLiteral(node, binding, relPath, line));
143	  for (const k of Object.keys(node)) {
144	    if (k === 'loc' || k === 'start' || k === 'end') continue;
145	    walk(node[k], valueChildBinding(node, k), relPath, violations);
146	  }
147	}
148	
149	function scanContent(relPath, src) {
150	  if (!useAcorn) throw new Error(relPath + ': acorn unavailable and BUDGET_CAPS refuses to approximate floor detection (an under-report is an unearned zero, Constitution Rule 4)');
151	  let ast;
152	  try { ast = acorn.parse(src, { ecmaVersion: 'latest', allowHashBang: true, allowReturnOutsideFunction: true, locations: true }); }
153	  catch (e) { throw new Error(relPath + ': acorn cannot parse this file: ' + e.message + ' (a parse failure is NOT zero violations)'); }
154	  const violations = [];
155	  walk(ast, null, relPath, violations);
156	  return { violations };
157	}
158	
159	function scanTree(dirs) {
160	  const violations = [];
161	  let scanned = 0;
162	  for (const dir of dirs) {
163	    const absDir = path.isAbsolute(dir) ? dir : path.join(ROOT, dir);
164	    for (const abs of listJsFiles(absDir, { skipDirs: SKIP_DIRS, skipTests: true })) {
165	      scanned++;
166	      const rel = path.relative(ROOT, abs).replace(/\\/g, '/');
167	      violations.push(...scanContent(rel, fs.readFileSync(abs, 'utf8')).violations);
168	    }
169	  }
170	  return { violations, scanned };
171	}
172	
173	function selfTest() {
174	  if (!useAcorn) {
175	    let refused = false;
176	    try { scanContent('selftest.js', 'const timeoutMs = Math.max(5000, x);'); }
177	    catch (e) { refused = true; /* FAIL-OPEN: the throw is the measured refusal signal (acorn mandatory), captured on purpose. */ }
178	    return { pass: refused, detail: refused ? 'no-acorn engine correctly REFUSES (exit 2), never a zero' : 'no-acorn engine did not refuse - it must never approximate' };
179	  }
180	  const bad = [
181	    'const timeoutMs = Math.max(5000, x);',                          // floor via binding name
182	    'f(a, Math.max(20000, Math.floor(deadlineMs * 0.6)), b);',       // floor via referenced identifier
183	    'setTimeout(fn, 130000);',                                       // oversize setTimeout
184	    'AbortSignal.timeout(200000);',                                  // oversize abort deadline
185	    'const DEADLINE_MS = 200000;',                                   // oversize budget constant
186	  ];
187	  const good = [
188	    'const width = Math.min(12, concurrency);',   // a cap, not a floor
189	    'const n = Math.max(0, count);',              // Math.max but not budget-associated
190	    'setTimeout(fn, 5000);',                       // in-budget timeout
191	    'const CORPUS_MAX_CHARS = 500000;',            // a char ceiling, not a time budget
192	    'AbortSignal.timeout(12000);',                 // in-budget deadline
193	  ];
194	  const badOk = bad.every((s) => scanContent('t.js', s).violations.length === 1);
195	  const goodOk = good.every((s) => scanContent('t.js', s).violations.length === 0);
196	  return {
197	    pass: badOk && goodOk,
198	    detail: (badOk && goodOk)
199	      ? 'catches Math.max floors on budget values (by binding name and by referenced identifier) and >120s setTimeout/AbortSignal/budget-constant literals; clears Math.min caps, in-budget timeouts and non-time ceilings (engine: acorn)'
200	      : 'FAILED: badOk=' + badOk + ' goodOk=' + goodOk,
201	  };
202	}
203	
204	function toFindings(violations) {
205	  return violations.map((v) => ({
206	    tool: 'budget-caps', ruleId: 'budget-caps/' + v.kind, file: v.file,
207	    startLine: v.line, endLine: v.line, level: 'error', message: v.message, snippet: v.kind,
208	  }));
209	}
210	
211	function main() {
212	  runGateCli({
213	    name: 'budget-caps',
214	    selfTest,
215	    scan: scanTree,
216	    toFindings,
217	    scanDirs: SCAN_DIRS,
218	    summary: (r) => r.scanned + ' evidence files, ' + r.violations.length + ' budget-floor/oversize-deadline violation(s) (engine: ' + (useAcorn ? 'acorn' : 'refuse') + ')',
219	    calibrateSummary: (r) => r.scanned + ' fixture files, ' + r.violations.length + ' seeded floor/oversize-deadline(s) found',
220	    violationLine: (v) => 'BUDGET [' + v.kind + '] ' + v.file + ':' + v.line + '  ' + v.message,
221	  });
222	}
223	
224	if (require.main === module) main();
225	
226	module.exports = { scanContent, scanTree, selfTest, toFindings, isBudgetFloor, isMathMax, THRESHOLD_MS };
