267	  if (strict) {
268	    return { entries: [{ name: cal.name, status: 'FAIL', detail: `${detail} - strict mode: a fixture without a live checker is an unearned zero` }], failed: 1, skipped: 0 };
269	  }
270	  return { entries: [{ name: cal.name, status: 'SKIPPED', detail: `${detail} - tools/ agent has not landed this gate yet; CI must flip to --strict when it does` }], failed: 0, skipped: 1 };
271	}
