'use strict';
// coverage-contract.test.js - coverage as blocking data, and the C-044 anchored-classify proof.
//
// The seeded p3-crawl-substring-classify fixture is the load-bearing case: classify() must anchor on path
// tokens (/feedback is not 'fees', /cost-of-living is not 'pricing'), never a loose substring, so coverage
// is not over-credited and a breach never fires on a page the crawl only THOUGHT it had.

const test = require('node:test');
const assert = require('node:assert');
const fs = require('node:fs');
const path = require('node:path');

const cov = require('./coverage-contract.js');

const FIX = path.join(__dirname, '..', '..', 'eval', 'calibration-known-bad', 'fixtures');
function loadFixture(name) { return JSON.parse(fs.readFileSync(path.join(FIX, name), 'utf8')); }

test('C-044: classify anchors on path tokens, never substrings (p3-crawl-substring-classify)', () => {
  const fx = loadFixture('p3-crawl-substring-classify.json');
  for (const c of fx.cases) {
    assert.equal(cov.classify(c.url), c.expect, c.url + ' must classify as ' + c.expect);
    if (c.trap) assert.notEqual(cov.classify(c.url), c.trap, c.url + ' must NEVER classify as the substring trap ' + c.trap);
  }
});

test('pagePath strips scheme/host/query/fragment to a normalised leading-slash path', () => {
  assert.equal(cov.pagePath('https://x.example/Privacy-Policy?a=1#top'), '/privacy-policy');
  assert.equal(cov.pagePath({ url: 'https://x.example/our/fees' }), '/our/fees');
  assert.equal(cov.pagePath('https://x.example/'), '/');
});

test('classify: the homepage and general pages', () => {
  assert.equal(cov.classify('https://x.example/'), 'homepage');
  assert.equal(cov.classify('https://x.example/index.html'), 'homepage');
  assert.equal(cov.classify('https://x.example/some/random/page'), 'other');
});

test('computeCoverage: enough required classes -> assessable, too few -> screened, none -> screened', () => {
  const assessable = cov.computeCoverage([{ url: 'https://x/' }, { url: 'https://x/privacy' }], null);
  assert.equal(assessable.render_class, 'assessable');
  assert.ok(assessable.fetched_classes.includes('privacy'));
  assert.equal(assessable.reachable, true);

  const screened = cov.computeCoverage([{ url: 'https://x/about' }], 'law-firms');
  assert.equal(screened.render_class, 'screened', 'a law firm with only an about page has too little coverage');

  const empty = cov.computeCoverage([], null);
  assert.equal(empty.render_class, 'screened');
  assert.equal(empty.reachable, false);
});

test('coverageFor: a rule whose needed page-class was crawled is covered; a missing one is screened', () => {
  const rules = [{ id: 'R1', website_obligations: [{ evidence_type: 'presence', duty: 'publish a complaints procedure', elements: ['complaints'] }] }];
  const covered = cov.coverageFor(rules, [{ url: 'https://x/complaints' }]);
  assert.equal(covered.rules[0].state, 'covered');

  const screened = cov.coverageFor(rules, [{ url: 'https://x/' }]);
  assert.equal(screened.rules[0].state, 'screened');
  assert.equal(cov.isScreened(screened, 'R1'), true);
});

test('coverageFor: a register/behavioural rule with no on-page text obligation is never gated by the crawl', () => {
  const rules = [{ id: 'REG', website_obligations: [{ evidence_type: 'register', duty: 'be on the FCA register' }] }];
  const out = cov.coverageFor(rules, []);
  assert.equal(out.rules[0].state, 'covered');
  assert.match(out.rules[0].reason, /non-crawl-evidence/);
});

test('INTERLOCK: a page-class living only in an unparsed document screens the obligation (C-033)', () => {
  const rules = [{ id: 'PRIV', website_obligations: [{ evidence_type: 'absence', duty: 'publish a privacy policy', elements: ['privacy'] }] }];
  const out = cov.coverageFor(rules, [{ url: 'https://x/' }], { unparsedClasses: new Set(['privacy']) });
  assert.equal(out.rules[0].state, 'screened');
  assert.match(out.rules[0].reason, /unparsed document/);
});

test('INTERLOCK: an absence claim on a truncated corpus is demoted to needs-review (C-024)', () => {
  const rules = [{ id: 'PRIV', website_obligations: [{ evidence_type: 'absence', duty: 'privacy policy present', elements: ['privacy'] }] }];
  const out = cov.coverageFor(rules, [{ url: 'https://x/privacy' }], { truncated: true });
  assert.equal(out.rules[0].state, 'screened');
  assert.match(out.rules[0].reason, /truncated/);
});

test('applyCoverage drops breach ("miss") findings when the SITE coverage is screened', () => {
  const findings = [{ id: 'a', status: 'miss' }, { id: 'b', status: 'hit' }];
  const screened = { render_class: 'screened' };
  const assessable = { render_class: 'assessable' };
  assert.deepEqual(cov.applyCoverage(findings, screened).map((f) => f.id), ['b']);
  assert.deepEqual(cov.applyCoverage(findings, assessable).map((f) => f.id), ['a', 'b']);
});

'use strict';
// extract.test.js - the ONE producer of stripped visible text and the content classifier.

const test = require('node:test');
const assert = require('node:assert');

const ex = require('./extract.js');

test('stripHtml keeps visible text only: script/style/noscript dropped, entities decoded, whitespace collapsed', () => {
  const html = '<html><head><style>.x{color:red}</style><script>var a=1<2;</script></head>'
    + '<body><h1>Hello&nbsp;&amp; welcome</h1><p>Line one</p><p>Line two</p><noscript>enable js</noscript></body></html>';
  const text = ex.stripHtml(html);
  assert.ok(!/color:red|var a/.test(text), 'script/style contents never enter the corpus (C-012)');
  assert.ok(!/enable js/.test(text), 'noscript is dropped');
  assert.match(text, /Hello & welcome/);
  assert.match(text, /Line one\nLine two/, 'block closers become newlines so footer lines survive');
});

test('stripHtml tolerates whitespace in closing tags (</script >)', () => {
  assert.ok(!/secret/.test(ex.stripHtml('<script >var s="secret"</script >visible')));
});

test('decodeEntities: named, numeric decimal, numeric hex, and malformed references', () => {
  assert.equal(ex.decodeEntities('a&amp;b'), 'a&b');
  assert.equal(ex.decodeEntities('&#65;&#x42;'), 'AB');
  assert.equal(ex.decodeEntities('&pound;10'), '£10');
  assert.equal(ex.decodeEntities('&notareal;'), '&notareal;', 'an unknown entity is left intact, never guessed');
});

test('extractTitle and extractFooterText (the mandatory disclosure surface, C-034)', () => {
  const html = '<html><head><title>  Acme &amp; Co  </title></head><body>x<footer>Acme Ltd, company number 01234567.<br>Registered in England.</footer></body></html>';
  assert.equal(ex.extractTitle(html), 'Acme & Co');
  const footer = ex.extractFooterText(html);
  assert.match(footer, /company number 01234567/);
  assert.match(footer, /Registered in England/);
});

test('extractHrefs keeps query strings (C-027) and is bounded', () => {
  const hrefs = ex.extractHrefs('<a href="/privacy?page_id=42">p</a><a href="/x#frag">x</a><a href="mailto:a@b.c">m</a>');
  assert.ok(hrefs.includes('/privacy?page_id=42'), 'a query string is never dropped');
  assert.ok(hrefs.includes('/x#frag'));
});

test('extractOgMeta surfaces og:site_name as a corpus value; buildPage sets page.ogSiteName', () => {
  const html = '<html><head><meta property="og:site_name" content="Acme &amp; Co"><meta property="og:title" content="Home"></head><body><p>Some visible body text for the corpus here.</p></body></html>';
  const og = ex.extractOgMeta(html);
  assert.equal(og.site_name, 'Acme & Co');
  assert.equal(og.title, 'Home');
  const page = ex.buildPage('https://x.example/', html);
  assert.equal(page.ogSiteName, 'Acme & Co');
});

test('buildPage omits ogSiteName when there is no og:site_name meta', () => {
  const page = ex.buildPage('https://x.example/', '<html><body><p>Body text with enough length to be content here.</p></body></html>');
  assert.equal('ogSiteName' in page, false);
});

test('extractJsonLd parses valid blocks and silently skips invalid JSON (never guesses)', () => {
  const html = '<script type="application/ld+json">{"@type":"Organization","name":"Acme"}</script>'
    + '<script type="application/ld+json">{bad json}</script>';
  const ld = ex.extractJsonLd(html);
  assert.equal(ld.length, 1);
  assert.equal(ld[0].name, 'Acme');
});

test('pageContentClass: real content is content', () => {
  assert.equal(ex.pageContentClass(200, '<html><body><h1>About us</h1><p>We are a firm providing services to clients across the country.</p></body></html>'), 'content');
});

test('pageContentClass: a login-dominant page is login, not content (C-031)', () => {
  const login = '<html><head><title>Sign in</title></head><body><form><input type="password" name="p"></form>Please log in.</body></html>';
  assert.equal(ex.pageContentClass(200, login), 'login');
});

test('pageContentClass: wall statuses and server errors never become content', () => {
  assert.equal(ex.pageContentClass(403, '<html><body>Access denied, please verify you are human.</body></html>'), 'challenge');
  assert.equal(ex.pageContentClass(500, '<html><body>error</body></html>'), 'error');
  assert.equal(ex.pageContentClass(404, '<html><body>not found</body></html>'), 'error');
});

test('pageContentClass: an empty SPA shell is empty, not content (C-032)', () => {
  assert.equal(ex.pageContentClass(200, '<html><body><div id="root"></div><script src="/app.js"></script></body></html>'), 'empty');
  assert.equal(ex.pageContentClass(200, '<html><body>   </body></html>'), 'empty');
});

'use strict';
// discover.test.js - link/sitemap discovery and the E-236 Tier-1-first-then-cap ordering (unit level).

const test = require('node:test');
const assert = require('node:assert');

const d = require('./discover.js');

const accepted = new Set(['example.com']);

test('classifyTier: Tier-1 legal wins over any lower tier; commercial and blog are ranked below', () => {
  assert.equal(d.classifyTier('https://example.com/privacy-policy'), 'tier1');
  assert.equal(d.classifyTier('https://example.com/modern-slavery-statement'), 'tier1');
  assert.equal(d.classifyTier('https://example.com/pricing'), 'tier2');
  assert.equal(d.classifyTier('https://example.com/blog/2024/post'), 'blog');
  assert.equal(d.classifyTier('https://example.com/gallery'), 'other');
  // a URL matching both tiers resolves to Tier-1 (legal wins).
  assert.equal(d.classifyTier('https://example.com/legal/pricing'), 'tier1');
});

test('discoverLinks: same-site only, query kept, fragments/mailto/tel dropped, deduped', () => {
  const html = [
    '<a href="/privacy?page_id=42">privacy</a>',
    '<a href="/privacy?page_id=42#section">dup</a>',
    '<a href="mailto:hi@example.com">mail</a>',
    '<a href="tel:+44">phone</a>',
    '<a href="https://evil.com/example.com">not us</a>',
    '<a href="https://blog.example.com/post">subdomain, same site</a>',
  ].join('');
  const links = d.discoverLinks(html, 'https://example.com', accepted);
  assert.ok(links.includes('https://example.com/privacy?page_id=42'), 'query strings are kept');
  assert.ok(links.some((u) => u.startsWith('https://blog.example.com/')), 'a same-registrable-site subdomain is in scope');
  assert.ok(!links.some((u) => u.includes('evil.com')), 'a hostile URL containing our name as a PATH is not same-site');
  assert.ok(!links.some((u) => /^mailto|^tel/.test(u)));
  assert.equal(new Set(links).size, links.length, 'links are deduped');
});

test('TIER-1-FIRST-THEN-CAP: a Tier-1 page discovered LAST survives a cap smaller than the candidate set', () => {
  // Four commercial pages discovered first, one legal page discovered LAST. cap = 3 (< 5 candidates + home).
  const discovered = [
    'https://example.com/services',
    'https://example.com/about',
    'https://example.com/pricing',
    'https://example.com/team',
    'https://example.com/data-protection', // Tier-1, discovered LAST
  ];
  const ordered = d.orderCandidates('https://example.com/', discovered, accepted, 3);
  assert.equal(ordered[0], 'https://example.com/', 'the homepage always leads');
  assert.ok(ordered.includes('https://example.com/data-protection'),
    'the Tier-1 page discovered last survives the cap because ranking precedes the slice');
  // no commercial page outranks the legal page.
  const legalIdx = ordered.indexOf('https://example.com/data-protection');
  for (const commercial of ['/services', '/about', '/pricing', '/team']) {
    const ci = ordered.indexOf('https://example.com' + commercial);
    assert.ok(ci === -1 || ci > legalIdx, commercial + ' never precedes the Tier-1 page');
  }
});

test('orderCandidates: the policy-path backstop is injected even when nothing links to it', () => {
  const ordered = d.orderCandidates('https://example.com/', [], accepted, 50);
  assert.ok(ordered.some((u) => u.endsWith('/privacy')), 'guessed policy paths backstop a site that omits them');
  assert.ok(ordered.some((u) => u.endsWith('/complaints')));
});

test('parseSitemapLocs splits page URLs from child sitemaps', () => {
  const xml = '<urlset><url><loc>https://example.com/a</loc></url><loc>https://example.com/sitemap-2.xml</loc></urlset>';
  const { pageUrls, childSitemaps } = d.parseSitemapLocs(xml);
  assert.deepEqual(pageUrls, ['https://example.com/a']);
  assert.deepEqual(childSitemaps, ['https://example.com/sitemap-2.xml']);
});

test('discoverSitemap: robots Sitemap: directive is followed, same-site pages returned (injected fetchXml)', async () => {
  const responses = {
    'https://example.com/robots.txt': 'User-agent: *\nSitemap: https://example.com/sm.xml\n',
    'https://example.com/sm.xml': '<urlset><url><loc>https://example.com/a</loc></url><url><loc>https://evil.com/b</loc></url></urlset>',
  };
  const fetchXml = (url) => Promise.resolve(responses[url] || '');
  const urls = await d.discoverSitemap('example.com', accepted, fetchXml);
  assert.deepEqual(urls, ['https://example.com/a'], 'off-site sitemap URLs are filtered out by the parsed-host door');
});

